using System;`nusing GestaoManutencao.Core.Domain;`nusing GestaoManutencao.Core.Interfaces;`nusing GestaoManutencao.Core.Exceptions;`n`nnamespace GestaoManutencao.Core.States`n{`n    public class EstadoAberta : ISolicitacaoState`n    {`n        public string Nome => "Aberta";`n`n        public void AtribuirTecnico(SolicitacaoManutencao solicitacao, Tecnico tecnico)`n        {`n            if (!tecnico.PossuiEspecialidade(solicitacao.Equipamento.EspecialidadeRequerida))`n                throw new TecnicoIncompativelException($"O tecnico {tecnico.Nome} nao possui a especialidade {solicitacao.Equipamento.EspecialidadeRequerida} exigida pelo equipamento.");`n`n            solicitacao.ForcarAtribuicaoTecnico(tecnico);`n            solicitacao.DefinirEstado(new EstadoEmAndamento());`n        }`n`n        public void AdicionarServico(SolicitacaoManutencao solicitacao, ServicoRealizado servico)`n        {`n            throw new TransicaoEstadoInvalidaException("Nao eh possivel registrar servicos em uma solicitacao que ainda esta Aberta e sem tecnico.");`n        }`n`n        public void Avancar(SolicitacaoManutencao solicitacao)`n        {`n            throw new TransicaoEstadoInvalidaException("Para avancar uma solicitacao Aberta, atribua um tecnico compativel.");`n        }`n`n        public void Cancelar(SolicitacaoManutencao solicitacao, string justificativa)`n        {`n            if (string.IsNullOrWhiteSpace(justificativa))`n                throw new ArgumentException("Justificativa eh obrigatoria para cancelamento.");`n`n            solicitacao.DefinirEstado(new EstadoCancelada(justificativa));`n        }`n    }`n}
